    arr.push({"text": x.CNAME, "href": u, "isvi": x.ISVC});
  });

  return arr;
}, []);

loginUrl:
function login() {
  const loginInfo = source.getLoginInfoMap();
  const username = loginInfo.get("账号");
  const password = loginInfo.get("密码");
  const timestamp = Date.now().toString();
  const aid = String(Packages.java.util.UUID.randomUUID())
    .replace(/-/g, "")
    .slice(0, 16);

  try {
    java.toast("正在登录...请稍候");
    const consumerKey = "LCREAD_ANDROID";
    const url = "http://a.lc1001.com/app/sso/pwdMdLogOn";
    const method = "GET";
    const secret = "XKrqBSeeEwgDy2pT";
    const md5Pwd = java.md5Encode(password).toLowerCase();
    const plain = `consumerKey=${consumerKey}` + `mdPwd=${md5Pwd}` + `pcd=${username}` + `timestamp=${timestamp}`;
    const sign = java.md5Encode(method + encodeURIComponent(url + plain) + secret).toLowerCase();
    const loginUrl = `${url}?consumerKey=${consumerKey}&timestamp=${timestamp}&sign=${sign}&pcd=${username}&mdPwd=${md5Pwd}&mType=XIAOMI-23049RAD8C&PACKINGCHANNEL=WANDOUJIA&imei=${aid}&androidID=${aid}`;
    java.log(loginUrl)
    const response = java.get(loginUrl, {});
    const responseBody = java.log(response.body());

    if (responseBody.includes("UNAME")) {
      java.log("登录成功");
      source.setVariable(responseBody);
      java.toast("✅登录成功");
    } else {
      java.log("❌登录失败，服务器返回: " + responseBody);
    }
  } catch (error) {
    java.log("❌登录失败: " + error.message);
  }
}

