@js:
var url = source.key
var result = [];
var push = (title, url, type) => result.push({
    title: title, url: url,
    style: {
    layout_flexGrow: 1,
    layout_flexBasisPercent: type } });

push("🏷️全部分类🏷️",null, 1)
try {
var a = org.jsoup.Jsoup.parse(java.ajax(url))
var lis = a.select(".newNav a");
for (var i = 0; i < lis.length; i++) {
    var text = lis[i].select('a').text();
    var href = url +String(lis[i].select('a').attr('href')).replace(/\d+\.html$/,"")+"<,index_{{page}}.html>";
    push(text, href, 0.33);
}
  java.toast("🎉 列表刷新完成，数据已更新❗");
  JSON.stringify(result); 

} catch (error) {
  java.toast("❌ 列表刷新失败，未获取到数据❗");
}

